args.script:
string[] spritePaths = new string[]
{
    "Assets/AchievementUI/ach_panel_bg.png",
    "Assets/AchievementUI/ach_header.png",
    "Assets/AchievementUI/ach_tab_green.png",
    "Assets/AchievementUI/ach_btn_claim.png",
    "Assets/AchievementUI/ach_icon_frame.png",
    "Assets/AchievementUI/ach_icon_trophy.png",
    "Assets/AchievementUI/ach_icon_swords.png",
    "Assets/AchievementUI/ach_icon_tree.png",
    "Assets/AchievementUI/ach_icon_flag.png",
    "Assets/AchievementUI/ach_icon_wizardhat.png",
    "Assets/AchievementUI/ach_icon_gold_trophy.png"
};

int changed = 0;
foreach (var path in spritePaths)
{
    var importer = UnityEditor.AssetImporter.GetAtPath(path) as UnityEditor.TextureImporter;
    if (importer == null)
    {
        UnityEngine.Debug.LogWarning($"No TextureImporter for {path}");
        continue;
    }
    if (importer.textureType != UnityEditor.TextureImporterType.Sprite)
    {
        importer.textureType = UnityEditor.TextureImporterType.Sprite;
        importer.spriteImportMode = UnityEditor.SpriteImportMode.Single;
        importer.spritePixelsPerUnit = 100;
        importer.SaveAndReimport();
        changed++;
        UnityEngine.Debug.Log($"Changed to Sprite: {path}");
    }
    else
    {
        UnityEngine.Debug.Log($"Already Sprite: {path}");
    }
}
UnityEngine.Debug.Log($"Done. Changed {changed} textures to Sprite.");

