var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var header = main.Find("Header");
var leftPanel = main.Find("LeftPanel");

// === 1. Header Trophy: add Image, set sprite, remove old Text ===
var trophyTf = header.Find("Trophy");
var iconTrophy = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_trophy.png");
if (trophyTf != null && iconTrophy != null)
{
    // Remove old Text
    var oldTxt = trophyTf.GetComponent<UnityEngine.UI.Text>();
    if (oldTxt != null) UnityEngine.Object.DestroyImmediate(oldTxt);

    // Add Image
    var img = trophyTf.gameObject.AddComponent<UnityEngine.UI.Image>();
    img.sprite = iconTrophy;
    img.SetNativeSize();
    UnityEngine.Debug.Log("Trophy: added Image + set icon");
}

// === 2. Tab icons: create Icon child with Image ===
string[,] tabData = new string[,]
{
    { "Tab_全部", "ach_icon_trophy" },
    { "Tab_成长", "ach_icon_tree" },
    { "Tab_战斗", "ach_icon_swords" },
    { "Tab_收集", "ach_icon_gold_trophy" },
    { "Tab_探索", "ach_icon_flag" },
    { "Tab_趣味", "ach_icon_wizardhat" }
};

for (int i = 0; i < tabData.GetLength(0); i++)
{
    var tabName = tabData[i, 0];
    var spriteName = tabData[i, 1];
    var tabTf = leftPanel.Find(tabName);
    if (tabTf == null) { UnityEngine.Debug.LogWarning($"Tab not found: {tabName}"); continue; }

    // Skip if Icon already exists
    if (tabTf.Find("Icon") != null) { UnityEngine.Debug.Log($"Icon already exists on {tabName}"); continue; }

    var sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>($"Assets/AchievementUI/{spriteName}.png");
    if (sprite == null) { UnityEngine.Debug.LogWarning($"Sprite not found: {spriteName}"); continue; }

    // Create Icon child
    var iconGo = new UnityEngine.GameObject("Icon");
    iconGo.transform.SetParent(tabTf, false);
    iconGo.transform.SetAsFirstSibling();

    var rt = iconGo.GetComponent<UnityEngine.RectTransform>();
    rt.sizeDelta = new UnityEngine.Vector2(28, 28);

    var iconImg = iconGo.AddComponent<UnityEngine.UI.Image>();
    iconImg.sprite = sprite;
    iconImg.SetNativeSize();

    UnityEngine.Debug.Log($"Created Icon on {tabName} -> {spriteName}");
}

UnityEngine.Debug.Log("=== Icons added! ===");

