var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var header = main.Find("Header");
var leftPanel = main.Find("LeftPanel");

var iconTrophy = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_trophy.png");
var iconSwords = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_swords.png");
var iconTree = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_tree.png");
var iconFlag = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_flag.png");
var iconWizardhat = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_wizardhat.png");
var iconGoldTrophy = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>("Assets/AchievementUI/ach_icon_gold_trophy.png");

// === 1. Trophy - set sprite on existing Image ===
var trophyTf = header.Find("Trophy");
var trophyImg = trophyTf.GetComponent<UnityEngine.UI.Image>();
if (trophyImg != null)
{
    trophyImg.sprite = iconTrophy;
    trophyImg.preserveAspect = true;
    UnityEngine.Debug.Log($"Trophy sprite set: {iconTrophy.name}");
}

// === 2. Tab icons ===
var iconSprites = new UnityEngine.Sprite[] { iconTrophy, iconTree, iconSwords, iconGoldTrophy, iconFlag, iconWizardhat };
var tabNames = new string[] { "Tab_全部", "Tab_成长", "Tab_战斗", "Tab_收集", "Tab_探索", "Tab_趣味" };

for (int i = 0; i < tabNames.Length; i++)
{
    var tabTf = leftPanel.Find(tabNames[i]);
    if (tabTf == null) { UnityEngine.Debug.LogWarning($"Tab not found: {tabNames[i]}"); continue; }

    // Check if Icon child already exists
    var existingIcon = tabTf.Find("Icon");
    if (existingIcon != null)
    {
        var eImg = existingIcon.GetComponent<UnityEngine.UI.Image>();
        if (eImg != null && iconSprites[i] != null)
        {
            eImg.sprite = iconSprites[i];
            UnityEngine.Debug.Log($"Updated icon on {tabNames[i]}");
        }
        continue;
    }

    // Create new Icon child
    if (iconSprites[i] == null) continue;

    var iconGo = new UnityEngine.GameObject("Icon", typeof(UnityEngine.RectTransform));
    iconGo.transform.SetParent(tabTf, false);
    iconGo.transform.SetAsFirstSibling();

    var rt = iconGo.GetComponent<UnityEngine.RectTransform>();
    rt.sizeDelta = new UnityEngine.Vector2(28, 28);

    var iconImg = iconGo.AddComponent<UnityEngine.UI.Image>();
    iconImg.sprite = iconSprites[i];
    iconImg.preserveAspect = true;

    UnityEngine.Debug.Log($"Created icon on {tabNames[i]} -> {iconSprites[i].name}");
}

UnityEngine.Debug.Log("=== All icons applied! ===");

