var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
achTf.gameObject.SetActive(false);
UnityEngine.Debug.Log($"AchievementPanel deactivated: active={achTf.gameObject.activeSelf}");

// Also check if AchievementItemUI references are wired
var item = achTf.Find("AchievementItem");
if (item != null)
{
    var ui = item.GetComponent<TowerDefense.UI.AchievementItemUI>();
    if (ui != null)
    {
        // Check serialized fields via reflection
        var type = ui.GetType();
        var fields = type.GetFields(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
        foreach (var f in fields)
        {
            if (f.IsDefined(typeof(SerializeField), false) || f.IsPublic)
            {
                var val = f.GetValue(ui);
                var isNull = val == null || val.Equals(null);
                UnityEngine.Debug.Log($"  {f.Name} ({f.FieldType.Name}): {(isNull ? "NULL" : val.ToString())}");
            }
        }
    }
    else
    {
        UnityEngine.Debug.LogWarning("No AchievementItemUI component on AchievementItem");
    }
}

