var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var header = main.Find("Header");
var leftPanel = main.Find("LeftPanel");
var item = achTf.Find("AchievementItem");

// === 1. Fix Trophy: sizeDelta way too big (2048x2048) ===
var trophyTf = header.Find("Trophy");
var trophyRt = trophyTf.GetComponent<UnityEngine.RectTransform>();
trophyRt.sizeDelta = new UnityEngine.Vector2(40, 40);
var trophyImg = trophyTf.GetComponent<UnityEngine.UI.Image>();
trophyImg.preserveAspect = true;
UnityEngine.Debug.Log($"Trophy fixed: sizeDelta=({trophyRt.sizeDelta.x},{trophyRt.sizeDelta.y})");

// === 2. Fix IconBg in AchievementItem: also 2048x2048 ===
var iconBgTf = item.Find("IconBg");
var iconBgRt = iconBgTf.GetComponent<UnityEngine.RectTransform>();
iconBgRt.sizeDelta = new UnityEngine.Vector2(60, 60);
var iconBgImg = iconBgTf.GetComponent<UnityEngine.UI.Image>();
iconBgImg.preserveAspect = true;
UnityEngine.Debug.Log($"IconBg fixed: sizeDelta=({iconBgRt.sizeDelta.x},{iconBgRt.sizeDelta.y})");

// === 3. Fix Tab Icons: they are all under Tab_全部, need to move to correct tabs ===
var tabNames = new string[] { "Tab_成长", "Tab_战斗", "Tab_收集", "Tab_探索", "Tab_趣味" };
var iconNames = new string[] { "ach_icon_tree", "ach_icon_swords", "ach_icon_gold_trophy", "ach_icon_flag", "ach_icon_wizardhat" };

var tabAll = leftPanel.Find("Tab_全部");
// Check how many Icons are under Tab_全部
int iconCount = 0;
for (int i = tabAll.childCount - 1; i >= 0; i--)
{
    var child = tabAll.GetChild(i);
    if (child.name == "Icon")
    {
        iconCount++;
        // Keep only the first Icon (index 0), destroy the rest
        if (iconCount > 1)
        {
            UnityEngine.Object.DestroyImmediate(child.gameObject);
            UnityEngine.Debug.Log($"Destroyed extra Icon #{iconCount} from Tab_全部");
        }
    }
}
UnityEngine.Debug.Log($"Tab_全部 has {iconCount} Icon children after cleanup");

// Now add Icon to each tab that doesn't have one
for (int i = 0; i < tabNames.Length; i++)
{
    var tabTf = leftPanel.Find(tabNames[i]);
    if (tabTf == null) continue;

    var existingIcon = tabTf.Find("Icon");
    if (existingIcon != null)
    {
        UnityEngine.Debug.Log($"{tabNames[i]} already has Icon");
        continue;
    }

    var sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Sprite>($"Assets/AchievementUI/{iconNames[i]}.png");
    if (sprite == null) continue;

    var iconGo = new UnityEngine.GameObject("Icon", typeof(UnityEngine.RectTransform));
    iconGo.transform.SetParent(tabTf, false);
    iconGo.transform.SetAsFirstSibling();

    var rt = iconGo.GetComponent<UnityEngine.RectTransform>();
    rt.sizeDelta = new UnityEngine.Vector2(28, 28);

    var img = iconGo.AddComponent<UnityEngine.UI.Image>();
    img.sprite = sprite;
    img.preserveAspect = true;

    UnityEngine.Debug.Log($"Created Icon on {tabNames[i]} -> {iconNames[i]}");
}

UnityEngine.Debug.Log("=== Fix complete! ===");

