// SetNativeSize to get correct proportions, then scale to desired height
img.SetNativeSize();
UnityEngine.Debug.Log($"After SetNativeSize: sizeDelta=({rt.sizeDelta.x},{rt.sizeDelta.y})");

// Now scale to target height while keeping aspect
float targetHeight = 36f;
float aspect = rt.sizeDelta.x / rt.sizeDelta.y;
float newWidth = targetHeight * aspect;
rt.sizeDelta = new UnityEngine.Vector2(newWidth, targetHeight);
UnityEngine.Debug.Log($"Final Trophy size: ({newWidth},{targetHeight})");

// Also check what the Title text looks like
var titleTf = header.Find("Title");
