args.script:
var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var leftPanel = achTf.Find("MainContainer/LeftPanel");

for (int i = 0; i < leftPanel.childCount; i++)
{
    var tab = leftPanel.GetChild(i);
    var icon = tab.Find("Icon");
    var label = tab.Find("Label");
    if (icon == null) continue;

    var iconRt = icon.GetComponent<UnityEngine.RectTransform>();
    // Make icon bigger: 24 -> 36
    iconRt.sizeDelta = new UnityEngine.Vector2(36, 36);

    // Position icon at the left side of the tab
    iconRt.anchorMin = new UnityEngine.Vector2(0, 0.5f);
    iconRt.anchorMax = new UnityEngine.Vector2(0, 0.5f);
    iconRt.pivot = new UnityEngine.Vector2(0, 0.5f);
    iconRt.anchoredPosition = new UnityEngine.Vector2(10, 0);

    // Move label text to the right of the icon
    if (label != null)
    {
        var labelRt = label.GetComponent<UnityEngine.RectTransform>();
        labelRt.anchorMin = new UnityEngine.Vector2(0, 0.5f);
        labelRt.anchorMax = new UnityEngine.Vector2(0, 0.5f);
        labelRt.pivot = new UnityEngine.Vector2(0, 0.5f);
        labelRt.anchoredPosition = new UnityEngine.Vector2(50, 0);
    }

    UnityEngine.Debug.Log($"Fixed {tab.name}: icon size=36, icon left-aligned, label right of icon");
}

