args.script:
var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var header = main.Find("Header");
var item = achTf.Find("AchievementItem");

// === 1. Title: 白色改深色, 加描边 ===
var titleTf = header.Find("Title");
var titleTxt = titleTf.GetComponent<UnityEngine.UI.Text>();
titleTxt.color = new UnityEngine.Color(0.15f, 0.12f, 0.08f); // 深棕色
titleTxt.fontSize = 42;
// Add Outline component for text shadow
var outline = titleTf.gameObject.GetComponent<UnityEngine.UI.Outline>();
if (outline == null) outline = titleTf.gameObject.AddComponent<UnityEngine.UI.Outline>();
outline.effectColor = new UnityEngine.Color(1f, 0.95f, 0.85f, 0.8f);
outline.effectDistance = new UnityEngine.Vector2(1, -1);
UnityEngine.Debug.Log("Title: dark color + outline added");

// === 2. CloseBtn: 改深色, 加背景圆 ===
var closeBtn = header.Find("CloseBtn");
var closeImg = closeBtn.GetComponent<UnityEngine.UI.Image>();
closeImg.color = new UnityEngine.Color(0.3f, 0.25f, 0.2f, 0.8f); // 深棕半透明
// CloseBtn 子对象 Text 颜色
for (int i = 0; i < closeBtn.childCount; i++)
{
    var t = closeBtn.GetChild(i).GetComponent<UnityEngine.UI.Text>();
    if (t != null)
    {
        t.color = UnityEngine.Color.white;
        t.fontSize = 28;
    }
}
UnityEngine.Debug.Log("CloseBtn: dark bg + white text");

// === 3. Header background: deeper color for contrast ===
var headerImg = header.GetComponent<UnityEngine.UI.Image>();
headerImg.color = new UnityEngine.Color(0.35f, 0.55f, 0.25f, 1f); // 更深的绿色
UnityEngine.Debug.Log("Header bg: deeper green");

// === 4. Panel bg: slightly warmer ===
var panelImg = achTf.GetComponent<UnityEngine.UI.Image>();
panelImg.color = new UnityEngine.Color(0.15f, 0.12f, 0.08f, 0.7f); // 深半透明遮罩
UnityEngine.Debug.Log("Panel bg: dark overlay");

// === 5. MainContainer bg: warm cream ===
var mainImg = main.GetComponent<UnityEngine.UI.Image>();
if (mainImg == null) mainImg = main.gameObject.AddComponent<UnityEngine.UI.Image>();
mainImg.color = new UnityEngine.Color(0.96f, 0.93f, 0.85f, 1f); // 暖米色
UnityEngine.Debug.Log("MainContainer: warm cream bg");

// === 6. Achievement item Name/Desc text: ensure good contrast ===
var nameTxt = item.Find("TextArea/Name").GetComponent<UnityEngine.UI.Text>();
nameTxt.color = new UnityEngine.Color(0.15f, 0.12f, 0.08f); // 深棕
var nameOutline = nameTxt.gameObject.GetComponent<UnityEngine.UI.Outline>();
if (nameOutline == null) nameOutline = nameTxt.gameObject.AddComponent<UnityEngine.UI.Outline>();
nameOutline.effectColor = new UnityEngine.Color(1f, 0.98f, 0.9f, 0.5f);
nameOutline.effectDistance = new UnityEngine.Vector2(0.5f, -0.5f);

var descTxt = item.Find("TextArea/Desc").GetComponent<UnityEngine.UI.Text>();
descTxt.color = new UnityEngine.Color(0.35f, 0.3f, 0.25f); // 中灰棕

UnityEngine.Debug.Log("Item text contrast fixed");

// === 7. RightSide RewardLabel: ensure visible ===
var rewardLabel = item.Find("RightSide/RewardLabel");
var rewardTxt = rewardLabel.GetComponent<UnityEngine.UI.Text>();
rewardTxt.color = new UnityEngine.Color(0.6f, 0.35f, 0.05f); // 金棕色
rewardTxt.fontSize = 18;

// ClaimBtn text
var claimBtn = item.Find("RightSide/ClaimBtn");
var claimLabel = claimBtn.Find("Label");
var claimTxt = claimLabel.GetComponent<UnityEngine.UI.Text>();
claimTxt.color = UnityEngine.Color.white;

UnityEngine.Debug.Log("Reward/Claim text colors fixed");

