var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var rightPanel = main.Find("RightPanel");
var scrollView = rightPanel.Find("ScrollView");
var content = scrollView.Find("Content");

// === 1. Add Viewport (missing!) ===
// ScrollView needs a Viewport with Mask for proper clipping
var viewport = scrollView.Find("Viewport");
if (viewport == null)
{
    // Check if ScrollView itself has ScrollRect
    var scrollRect = scrollView.GetComponent<UnityEngine.UI.ScrollRect>();
    if (scrollRect != null)
    {
        UnityEngine.Debug.Log($"ScrollRect: horizontal={scrollRect.horizontal} vertical={scrollRect.vertical} content={scrollRect.content?.name ?? "null"} viewport={scrollRect.viewport?.name ?? "null"}");
    }

    // Check for Scrollbar
    var scrollbar = scrollView.Find("Scrollbar");
    if (scrollbar != null)
    {
        UnityEngine.Debug.Log($"Scrollbar found: {scrollbar.name}");
        var sbImg = scrollbar.GetComponent<UnityEngine.UI.Image>();
        if (sbImg != null) UnityEngine.Debug.Log($"Scrollbar bg color: ({sbImg.color.r:F2},{sbImg.color.g:F2},{sbImg.color.b:F2},{sbImg.color.a:F2})");

        // Check sliding area
        var slidingArea = scrollbar.Find("Sliding Area");
        if (slidingArea != null)
        {
            var handle = slidingArea.Find("Handle");
            if (handle != null)
            {
                var hImg = handle.GetComponent<UnityEngine.UI.Image>();
                UnityEngine.Debug.Log($"Handle color: ({hImg.color.r:F2},{hImg.color.g:F2},{hImg.color.b:F2},{hImg.color.a:F2})");
            }
        }
    }
    else
    {
        UnityEngine.Debug.Log("No Scrollbar child");
    }
}

// Check content layout
var vlg = content.GetComponent<UnityEngine.UI.VerticalLayoutGroup>();
if (vlg != null)
{
    UnityEngine.Debug.Log($"VerticalLayout: spacing={vlg.spacing} padding=({vlg.padding.left},{vlg.padding.right},{vlg.padding.top},{vlg.padding.bottom}) childAlignment={vlg.childAlignment} childControlSize={vlg.childControlWidth},{vlg.childControlHeight} childForceExpand={vlg.childForceExpandWidth},{vlg.childForceExpandHeight}");
}
else
{
    UnityEngine.Debug.Log("No VerticalLayoutGroup on Content");
}

var csf = content.GetComponent<UnityEngine.UI.ContentSizeFitter>();
if (csf != null)
{
    UnityEngine.Debug.Log($"ContentSizeFitter: horizontal={csf.horizontalFit} vertical={csf.verticalFit}");
}
else
{
    UnityEngine.Debug.Log("No ContentSizeFitter on Content");
}

