args.script:
var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var main = achTf.Find("MainContainer");
var rightPanel = main.Find("RightPanel");
var scrollView = rightPanel.Find("ScrollView");
var scrollRect = scrollView.GetComponent<UnityEngine.UI.ScrollRect>();

// === 1. Add custom scrollbar ===
var scrollbarGo = new UnityEngine.GameObject("Scrollbar", typeof(UnityEngine.RectTransform));
scrollbarGo.transform.SetParent(scrollView, false);

var sbRt = scrollbarGo.GetComponent<UnityEngine.RectTransform>();
sbRt.anchorMin = new UnityEngine.Vector2(1f, 0f);
sbRt.anchorMax = new UnityEngine.Vector2(1f, 1f);
sbRt.pivot = new UnityEngine.Vector2(1f, 0.5f);
sbRt.sizeDelta = new UnityEngine.Vector2(12, 0);
sbRt.anchoredPosition = new UnityEngine.Vector2(-4, 0);

// Scrollbar bg
var sbBg = scrollbarGo.AddComponent<UnityEngine.UI.Image>();
sbBg.color = new UnityEngine.Color(0.75f, 0.7f, 0.6f, 0.5f);

var scrollbar = scrollbarGo.AddComponent<UnityEngine.UI.Scrollbar>();
scrollbar.direction = UnityEngine.UI.Scrollbar.Direction.BottomToTop;

// Sliding Area
var slidingGo = new UnityEngine.GameObject("Sliding Area", typeof(UnityEngine.RectTransform));
slidingGo.transform.SetParent(scrollbarGo, false);
var saRt = slidingGo.GetComponent<UnityEngine.RectTransform>();
saRt.anchorMin = UnityEngine.Vector2.zero;
saRt.anchorMax = UnityEngine.Vector2.one;
saRt.sizeDelta = new UnityEngine.Vector2(-4, -4);

// Handle
var handleGo = new UnityEngine.GameObject("Handle", typeof(UnityEngine.RectTransform));
handleGo.transform.SetParent(slidingGo, false);
var hRt = handleGo.GetComponent<UnityEngine.RectTransform>();
hRt.anchorMin = UnityEngine.Vector2.zero;
hRt.anchorMax = new UnityEngine.Vector2(1f, 0.3f); // initial size
hRt.sizeDelta = new UnityEngine.Vector2(0, 0);

var hImg = handleGo.AddComponent<UnityEngine.UI.Image>();
hImg.color = new UnityEngine.Color(0.5f, 0.42f, 0.3f, 0.9f); // warm brown

scrollbar.handleRect = hRt;
scrollbar.targetGraphic = hImg;

// Wire scrollbar to ScrollRect
scrollRect.verticalScrollbar = scrollbar;
scrollRect.verticalScrollbarVisibility = UnityEngine.UI.ScrollRect.ScrollbarVisibility.AutoHide;

UnityEngine.Debug.Log("Custom scrollbar added");

// === 2. Fix Content: need to account for scrollbar width ===
var content = scrollView.Find("Content");
var vlg = content.GetComponent<UnityEngine.UI.VerticalLayoutGroup>();
vlg.padding = new UnityEngine.RectOffset(10, 20, 10, 10); // right padding for scrollbar

UnityEngine.Debug.Log("Content padding adjusted for scrollbar");

// === 3. Mask on ScrollView for clipping ===
var mask = scrollView.GetComponent<UnityEngine.UI.Mask>();
if (mask == null)
{
    var svImg = scrollView.GetComponent<UnityEngine.UI.Image>();
    if (svImg == null)
    {
        svImg = scrollView.gameObject.AddComponent<UnityEngine.UI.Image>();
        svImg.color = UnityEngine.Color.clear;
    }
    mask = scrollView.gameObject.AddComponent<UnityEngine.UI.Mask>();
    mask.showMaskGraphic = false;
    UnityEngine.Debug.Log("Mask added to ScrollView");
}
else
{
    UnityEngine.Debug.Log("Mask already exists");
}

