args.script:
var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var item = achTf.Find("AchievementItem");

// === 1. Add background to AchievementItem for row distinction ===
var itemImg = item.GetComponent<UnityEngine.UI.Image>();
if (itemImg == null)
{
    itemImg = item.gameObject.AddComponent<UnityEngine.UI.Image>();
}
itemImg.color = new UnityEngine.Color(1f, 0.97f, 0.9f, 1f); // warm off-white

// Add LayoutElement to control item height
var layoutElem = item.GetComponent<UnityEngine.UI.LayoutElement>();
if (layoutElem == null) layoutElem = item.gameObject.AddComponent<UnityEngine.UI.LayoutElement>();
layoutElem.minHeight = 90;
layoutElem.preferredHeight = 90;

UnityEngine.Debug.Log("Item: bg + LayoutElement added");

// === 2. ClaimAllBtn: make more prominent ===
var main = achTf.Find("MainContainer");
var claimAllBtn = main.Find("ClaimAllBtn");
var claimAllImg = claimAllBtn.GetComponent<UnityEngine.UI.Image>();
if (claimAllImg != null)
{
    claimAllImg.color = new UnityEngine.Color(0.9f, 0.65f, 0.1f, 1f); // golden orange
}

// === 3. LeftPanel bg ===
var leftPanel = main.Find("LeftPanel");
var lpImg = leftPanel.GetComponent<UnityEngine.UI.Image>();
if (lpImg == null) lpImg = leftPanel.gameObject.AddComponent<UnityEngine.UI.Image>();
lpImg.color = new UnityEngine.Color(0.9f, 0.87f, 0.78f, 1f); // warm tan

// === 4. Progress bar styling ===
var progressRow = item.Find("TextArea/ProgressRow");
var sliderGo = progressRow.Find("ItemSlider");
if (sliderGo == null)
{
    // Try to find the slider by component
    for (int i = 0; i < progressRow.childCount; i++)
    {
        var child = progressRow.GetChild(i);
        var slider = child.GetComponent<UnityEngine.UI.Slider>();
        if (slider != null)
        {
            sliderGo = child;
            UnityEngine.Debug.Log($"Found slider: {child.name}");
            break;
        }
    }
}

if (sliderGo != null)
{
    // Background
    var bg = sliderGo.Find("Background");
    if (bg != null)
    {
        var bgImg = bg.GetComponent<UnityEngine.UI.Image>();
        bgImg.color = new UnityEngine.Color(0.8f, 0.75f, 0.65f, 1f); // warm grey
    }
    // Fill
    var fillArea = sliderGo.Find("Fill Area");
    if (fillArea != null)
    {
        var fill = fillArea.Find("Fill");
        if (fill != null)
        {
            var fillImg = fill.GetComponent<UnityEngine.UI.Image>();
            fillImg.color = new UnityEngine.Color(0.45f, 0.7f, 0.3f, 1f); // green
        }
    }
}

// === 5. ClaimBtn in item ===
var claimBtn = item.Find("RightSide/ClaimBtn");
var claimImg = claimBtn.GetComponent<UnityEngine.UI.Image>();
if (claimImg != null)
{
    claimImg.color = new UnityEngine.Color(0.85f, 0.6f, 0.1f, 1f); // golden
}

UnityEngine.Debug.Log("=== All visual improvements done! ===");

