var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var item = achTf.Find("AchievementItem");

// Check ALL text components in item recursively
void CheckTexts(UnityEngine.Transform tf, string indent)
{
    var txt = tf.GetComponent<UnityEngine.UI.Text>();
    if (txt != null)
    {
        UnityEngine.Debug.Log($"{indent}{tf.name}: \"{txt.text}\" size={txt.fontSize} color=({txt.color.r:F2},{txt.color.g:F2},{txt.color.b:F2},{txt.color.a:F2}) font={txt.font?.name ?? "null"}");
    }
    for (int i = 0; i < tf.childCount; i++)
        CheckTexts(tf.GetChild(i), indent + "  ");
}

CheckTexts(item, "");

// Check ClaimAllBtn text
var main = achTf.Find("MainContainer");
var claimAll = main.Find("ClaimAllBtn");
CheckTexts(claimAll, "  ");

// Check if ClaimBtn has Button component that might override text color
var claimBtn = item.Find("RightSide/ClaimBtn");
var btn = claimBtn.GetComponent<UnityEngine.UI.Button>();
if (btn != null)
{
    var colors = btn.colors;
    UnityEngine.Debug.Log($"ClaimBtn colors: normal=({colors.normalColor.r:F2},{colors.normalColor.g:F2},{colors.normalColor.b:F2},{colors.normalColor.a:F2})");
    UnityEngine.Debug.Log($"ClaimBtn colors: disabled=({colors.disabledColor.r:F2},{colors.disabledColor.g:F2},{colors.disabledColor.b:F2},{colors.disabledColor.a:F2})");
    UnityEngine.Debug.Log($"ClaimBtn interactable={btn.interactable}");
}

