var canvas = UnityEngine.GameObject.Find("Canvas");
var achTf = canvas.transform.Find("AchievementPanel");
var item = achTf.Find("AchievementItem");
var main = achTf.Find("MainContainer");

// === 1. RewardLabel template: replace emoji ===
var rewardLabel = item.Find("RightSide/RewardLabel");
var rewardTxt = rewardLabel.GetComponent<UnityEngine.UI.Text>();
rewardTxt.text = "[金]x100  [钻]x10"; // plain text instead of emoji

// === 2. IconSymbol: replace emoji ===
var iconSymbol = item.Find("IconBg/IconSymbol");
if (iconSymbol != null)
{
    var symTxt = iconSymbol.GetComponent<UnityEngine.UI.Text>();
    symTxt.text = "";
    symTxt.enabled = false; // disable, we use sprite now
    UnityEngine.Debug.Log("IconSymbol: disabled (using sprite instead)");
}

// === 3. ClaimBtn Label: ensure dark text on gold button ===
var claimBtn = item.Find("RightSide/ClaimBtn");
var claimLabel = claimBtn.Find("Label");
var claimTxt = claimLabel.GetComponent<UnityEngine.UI.Text>();
claimTxt.color = new UnityEngine.Color(0.2f, 0.12f, 0.02f); // dark brown on gold bg

// === 4. ClaimAll Label ===
var claimAll = main.Find("ClaimAllBtn");
var claimAllLabel = claimAll.Find("Label");
var claimAllTxt = claimAllLabel.GetComponent<UnityEngine.UI.Text>();
claimAllTxt.color = new UnityEngine.Color(0.2f, 0.12f, 0.02f); // dark brown
claimAllTxt.text = "一键领取";

// === 5. RewardLabel: fix text overflow ===
rewardTxt.horizontalOverflow = UnityEngine.UI.HorizontalWrapMode.Wrap;
rewardTxt.verticalOverflow = UnityEngine.UI.VerticalWrapMode.Truncate;

UnityEngine.Debug.Log("=== Template text & colors fixed! ===");

